css:
.loader {
  width: 240px;
  height: 190px;
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  overflow: hidden;
}
.carousel {
  --w: 48px;
  --h: 72px;
  --translateZ: 135px;
  --rotateX: -15deg;
  --perspective: 850px;
  position: absolute;
  width: var(--w);
  height: var(--h);
  transform-style: preserve-3d;
  transform: perspective(var(--perspective));
  animation: neonCarouselSpin 16s linear infinite;
}
@keyframes neonCarouselSpin {
  from { transform: perspective(var(--perspective)) rotateX(var(--rotateX)) rotateY(0); }
  to { transform: perspective(var(--perspective)) rotateX(var(--rotateX)) rotateY(1turn); }
}
.card {
  position: absolute;
  border: 2px solid rgba(var(--color-card));
  border-radius: 12px;
  overflow: hidden;
  inset: 0;
  transform: rotateY(calc((360deg / var(--quantity)) * var(--index))) translateZ(var(--translateZ));
  box-shadow: 0 0 12px rgba(var(--color-card), .65);
}
.img {
  width: 100%;
  height: 100%;
  background: radial-gradient(circle, rgba(var(--color-card), .25) 0%, rgba(var(--color-card), .75) 80%, rgba(var(--color-card), .95) 100%);
}
